INSERT INTO sys_logs (
    log_level, log_content, create_time, class_name, method_name, request_url, username, ip
) VALUES (
    #{logLevel}, #{logContent}, #{createTime}, #{className}, #{methodName}, #{requestUrl}, #{username}, #{ip}
)

mapper.select:
SELECT * FROM sys_logs WHERE 1=1

    AND username LIKE CONCAT('%', #{username}, '%')


    AND log_level = #{logLevel}


    AND (log_content LIKE CONCAT('%', #{search}, '%') OR request_url LIKE CONCAT('%', #{search}, '%') OR class_name LIKE CONCAT('%', #{search}, '%') OR method_name LIKE CONCAT('%', #{search}, '%'))

ORDER BY create_time DESC LIMIT #{size} OFFSET #{offset}
